import{_ as t,o as e,c as o,a2 as r}from"./chunks/framework.Crpw6aS5.js";const d=JSON.parse('{"title":"ISCAR/IMC","description":"","frontmatter":{"title":"ISCAR/IMC"},"headers":[],"relativePath":"03_companies/ISCAR-IMC.md","filePath":"03_companies/ISCAR-IMC.md"}'),i={name:"03_companies/ISCAR-IMC.md"};function n(l,a,s,c,h,p){return e(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="iscar-imc" tabindex="-1">ISCAR/IMC <a class="header-anchor" href="#iscar-imc" aria-label="Permalink to &quot;ISCAR/IMC&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><ul><li><strong>首次提及</strong>: 2006年</li><li><strong>持股情况</strong>: 2006年7月5日收购80%</li><li><strong>行业</strong>: 金属切削工具制造</li><li><strong>英文名</strong>: ISCAR / IMC (International Metalworking Companies)</li><li><strong>总部</strong>: 以色列</li><li><strong>董事长</strong>: 埃坦·韦特海默（Eitan Wertheimer）</li><li><strong>CEO</strong>: 雅各布·哈帕兹（Jacob Harpaz）</li></ul><h2 id="巴菲特论述" tabindex="-1">巴菲特论述 <a class="header-anchor" href="#巴菲特论述" aria-label="Permalink to &quot;巴菲特论述&quot;">​</a></h2><p>2006年7月5日收购80%股权，这是伯克希尔首次海外收购。ISCAR是以色列切削工具公司，在61个国家运营。</p><p>后更名为IMC (International Metalworking Companies)，成为伯克希尔&quot;五大非保险业务支柱&quot;之一。</p><p>2009年，ISCAR收购日本领先小工具生产商Tungaloy，进一步扩展全球业务。</p><h2 id="投资意义" tabindex="-1">投资意义 <a class="header-anchor" href="#投资意义" aria-label="Permalink to &quot;投资意义&quot;">​</a></h2><p>这次收购标志着巴菲特开始将投资版图扩展到美国以外。ISCAR代表了高质量的工业制造企业，拥有强大的技术优势和全球市场地位。巴菲特特别赞赏韦特海默家族的管理能力，这是一个典型的&quot;买入并持有&quot;的优秀企业。</p><h2 id="关联年份" tabindex="-1">关联年份 <a class="header-anchor" href="#关联年份" aria-label="Permalink to &quot;关联年份&quot;">​</a></h2><p>2006, 2009, 2010</p>',11)])])}const I=t(i,[["render",n]]);export{d as __pageData,I as default};
